def get_ludic(n):
    if n < 1: 
        return []

    # Initialize the list of ludic numbers
    ludics = [True] * (n + 1)
    ludics[0], ludics[1] = False, False  # 0 and 1 are not ludic

    # Start from the first number that is not marked as ludic
    i = 2
    while True:
        if ludics[i]:
            # Mark multiples of the current ludic number as non-ludic
            for j in range(i*i, n + 1, i):
                ludics[j] = False
        # Move to the next number that is not marked as ludic
        i += 1
        if i > n:
            break

    # Extract the ludic numbers
    return [i for i in range(n + 1) if ludics[i]]

