def bell_Number(n):
    Bell_Num = [0] * (n + 1)
    Bell_Num[0] = 1
    for i in range(1, n + 1):
        Bell_Num[i] = 0
        for j in range(i):
            Bell_Num[i] += Bell_Num[j] * Bell_Num[i - j - 1]
    return Bell_Num[n]

