def bell_Number(n):
    dp = [[0] * (n + 1) for _ in range(n + 1)]

    for i in range(n + 1):
        dp[i][i] = 1

    for i in range(n + 1):
        for j in range(i):
            dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j]

    return dp[n][0]

