def lcs_of_three(X, Y, Z, m, n, o):
    # Create a 3D table to store lengths of longest common subsequence
    dp = [[[0] * (o + 1) for _ in range(n + 1)] for _ in range(m + 1)]

    # Build dp table from bottom up
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            for k in range(1, o + 1):
                if X[i - 1] == Y[j - 1] == Z[k - 1]:
                    dp[i][j][k] = dp[i - 1][j - 1][k - 1] + 1
                else:
                    dp[i][j][k] = max(dp[i - 1][j][k], dp[i][j - 1][k], dp[i][j][k - 1])

    return dp[m][n][o]

def lcs_of_three(A, B, C, m, n, p):
    # Create a 3D array to store lengths of longest common subsequences
    L = [[[0] * (p + 1) for _ in range(n + 1)] for _ in range(m + 1)]

    # Build the L[m][n][p] table in bottom-up fashion
    for i in range(m + 1):
        for j in range(n + 1):
            for k in range(p + 1):
                if i == 0 or j == 0 or k == 0:
                    L[i][j][k] = 0
                elif A[i - 1] == B[j - 1] and B[j - 1] == C[k - 1]:
                    L[i][j][k] = L[i - 1][j - 1][k - 1] + 1
                else:
                    L[i][j][k] = max(L[i - 1][j][k], L[i][j - 1][k], L[i][j][k - 1])

    return L[m][n][p]

