def lcs_of_three(X, Y, Z):
    m = len(X)
    n = len(Y)
    o = len(Z)

    # Create a 3D array to store results of subproblems
    L = [[[0] * (o + 1) for _ in range(n + 1)] for _ in range(m + 1)]

    # Build L[m+1][n+1][o+1] in bottom-up fashion
    for i in range(m + 1):
        for j in range(n + 1):
            for k in range(o + 1):
                if i == 0 or j == 0 or k == 0:
                    L[i][j][k] = 0
                elif X[i - 1] == Y[j - 1] == Z[k - 1]:
                    L[i][j][k] = L[i - 1][j - 1][k - 1] + 1
