def lcs_of_three(A, B, C):
    # Initialize a 3D array to store lengths of longest common subsequences
    L = [[[0] * (len(C) + 1) for _ in range(len(B) + 1)] for _ in range(len(A) + 1)]

    # Build the 3D table in bottom-up manner
    for i in range(1, len(A) + 1):
        for j in range(1, len(B) + 1):
            for k in range(1, len(C) + 1):
                if A[i - 1] == B[j - 1] == C[k - 1]:
                    L[i][j][k] = L[i - 1][j - 1][k - 1] + 1
                else:
                    L[i][j][k] = max(L[i - 1][j][k], L[i][j - 1][k], L[i][j][k - 1])

    # The length of the longest common subsequence of A, B and C is at L[len(A)][len(B)][len(C)]
    return L[len(A)][len(B)][len(C)]

