def is_polite(n):
    # If n is less than or equal to 2, it's not a polite number
    if n <= 2:
        return False

    # Iterate to find the nth polite number
    for i in range(3, n * 2 + 1):
        count = 0
        # Check divisibility by numbers from 2 to i-1
        for j in range(2, i):
            if i % j == 0:
                count += 1

        # If divisible by more than one number, it's not polite
        if count > 1:
            continue
        else:
            # If it's polite, return i
            return i

    # This line should theoretically never be reached
    return False

