def rgb_to_hsv(R, G, B):
    R /= 255
    G /= 255
    B /= 255
    Cmax = max(R, G, B)
    Cmin = min(R, G, B)
    delta = Cmax - Cmin
    V = Cmax
    if delta == 0:
        H = 0
    elif Cmax == R:
        H = 60 * ((G - B) / delta) % 360
    elif Cmax == G:
        H = 60 * ((B - R) / delta) + 120
    else:
