    # Normalize RGB values to the range [0, 1]
    r, g, b = r / 255.0, g / 255.0, b / 255.0
    mx = max(r, g, b)
    mn = min(r, g, b)
    diff = mx - mn
    if mx == mn:
        h = 0
    elif mx == r:
        h = (60 * ((g - b) / diff) + 360) % 360
    elif mx == g:
        h = (60 * ((b - r) / diff) + 120) % 360
    else:  # mx == b
        h = (60 * ((r - g) / diff) + 240) % 360
    if mx == 0:
        s = 0
    else:
        s = (diff / mx) * 100
    v = mx * 100
    return h, s, v

def rgb_to_hsv(R, G, B):
    if R == G == B == 0:
        return (0, 0.0, 0.0)
    min_val = min(R, G, B)
    max_val = max(R, G, B)
    diff = max_val - min_val
    V = max_val / 255.0
    if diff == 0:
        H = S = 0.0
    else:
        if max_val == R:
            H = ((G - B) / diff) % 6
        elif max_val == G:
            H = ((B - R) / diff) + 2
        else:
            H = ((R - G) / diff) + 4
        H *= 60
        S = diff / max_val
    return (H, S, V)

